        Source: ir.Handle{Node: sourceNode.Key, Param: outputName},
        Target: result.input,
        Kind:   ir.EdgeKindContinuous,
    })
} else {
    src := prevOutputHandle
    if src == (ir.Handle{}) {
        src = ir.Handle{Node: sourceNode.Key, Param: outputName}
    }
    edges = append(edges, ir.Edge{
        Source: src,
        Target: result.input,
        Kind:   ir.EdgeKindContinuous,
    })
}
```

Worth addressing as a follow-up, or adding a test that starts a routing-table branch with a void function.

